# worker.py
import os

worker_id = os.getenv("WORKER_ID")
GLOBAL_RPM = 10000
N = 10  # number of workers (static)
PER_WORKER_RPM = GLOBAL_RPM / N

class LocalRateLimiter:
    def __init__(self, limit: int):
        self.limit = limit
        self.count = 0

    def can_send(self):
        if self.count >= self.limit:
            return False
        self.count += 1
        return True

limiter = LocalRateLimiter(PER_WORKER_RPM)

def send_request():
    if limiter.can_send():
        # send request
        pass
    else:
        # block or retry
        pass
